"use client"

import * as React from "react"
import { ClubCardPreview } from "./club-card-preview"
import { ClubCardDrawer } from "./club-card-drawer"
import type { ClubCardProps, DrawerDirection } from "./types"

function useResolvedDirection(direction: DrawerDirection) {
  const [isDesktop, setIsDesktop] = React.useState(false)

  React.useEffect(() => {
    const mediaQuery = window.matchMedia("(min-width: 768px)")
    const sync = () => setIsDesktop(mediaQuery.matches)
    sync()
    mediaQuery.addEventListener("change", sync)
    return () => mediaQuery.removeEventListener("change", sync)
  }, [])

  return direction === "auto" ? (isDesktop ? "right" : "bottom") : direction
}

export function ClubCard({
  domain,
  name,
  imageUrl,
  miniDescription,
  shouldCompress = false,
  showSuccessIcon = false,
  ctaText,
  cardCtaText,
  drawerCtaText,
  onCtaClick,
  totalMembers,
  detailPoints,
  detailDescription,
  drawerDirection = "auto",
  ctaTheme,
  drawerBottomInsetClassName,
  drawerBodyClassName,
  drawerPinFooter = true,
  drawerFooterClassName,
  className,
}: ClubCardProps) {
  const [open, setOpen] = React.useState(false)
  const resolvedDirection = useResolvedDirection(drawerDirection)
  const resolvedCardCtaText = cardCtaText ?? ctaText
  const resolvedDrawerCtaText = drawerCtaText ?? ctaText

  const handleCtaClick = () => {
    setOpen(true)
  }

  return (
    <>
      <ClubCardPreview
        domain={domain}
        name={name}
        imageUrl={imageUrl}
        miniDescription={miniDescription}
        shouldCompress={shouldCompress}
        showSuccessIcon={showSuccessIcon}
        ctaText={resolvedCardCtaText}
        ctaTheme={ctaTheme}
        onCtaClick={handleCtaClick}
        className={className}
      />
      <ClubCardDrawer
        domain={domain}
        name={name}
        imageUrl={imageUrl}
        shouldCompress={shouldCompress}
        totalMembers={totalMembers}
        detailPoints={detailPoints}
        detailDescription={detailDescription}
        ctaText={resolvedDrawerCtaText}
        ctaTheme={ctaTheme}
        onCtaClick={onCtaClick}
        open={open}
        onOpenChange={setOpen}
        resolvedDirection={resolvedDirection}
        drawerBottomInsetClassName={drawerBottomInsetClassName}
        drawerBodyClassName={drawerBodyClassName}
        drawerPinFooter={drawerPinFooter}
        drawerFooterClassName={drawerFooterClassName}
      />
    </>
  )
}

export type { ClubCardProps, DrawerDirection, CtaTheme } from "./types"

import { cn } from "@/lib/utils";

import type { ClubCardProps } from "./types";
import { CardCtaButton } from "../shared/card-cta-button";
import { CheckCircle } from "@phosphor-icons/react";
import { toRichPreviewText } from "./rich-content";

function toCapitalizedWords(value: string) {
  return value.replace(/\b\w/g, (char) => char.toUpperCase());
}

type ClubCardPreviewProps = Pick<
  ClubCardProps,
  | "domain"
  | "name"
  | "imageUrl"
  | "miniDescription"
  | "shouldCompress"
  | "showSuccessIcon"
  | "ctaText"
  | "ctaTheme"
  | "className"
> & {
  onCtaClick: () => void;
};

export function ClubCardPreview({
  domain,
  name,
  imageUrl,
  miniDescription,
  shouldCompress,
  showSuccessIcon,
  ctaText,
  ctaTheme,
  onCtaClick,
  className,
}: ClubCardPreviewProps) {
  const resolvedName = toCapitalizedWords(name);
  const resolvedDomain = toCapitalizedWords(domain);
  const resolvedMiniDescription = toRichPreviewText(miniDescription);
  const resolvedCtaText = toCapitalizedWords(ctaText);

  const iconBlock = (
    <div className="relative shrink-0 self-start">
      <div className="flex size-12 shrink-0 items-center justify-center rounded-full bg-[#EBF5FF]">
        <img
          src={imageUrl}
          alt={resolvedName}
          className="size-6 shrink-0 rounded-lg object-cover"
        />
      </div>
      {showSuccessIcon ? (
        <span className="absolute left-1/2 top-full -translate-x-1/2 -translate-y-1/2 shrink-0 rounded-full bg-white">
          <CheckCircle size={16} weight="fill" color="#00B178" />
        </span>
      ) : null}
    </div>
  );

  if (shouldCompress) {
    return (
      <div
        onClick={onCtaClick}
        className={cn(
          "font-poppins flex h-full w-full min-w-0 max-w-[300px] flex-col cursor-pointer rounded-[12px] border border-[#E5E7EB] bg-white p-4",
          className,
        )}
      >
        <div className="flex min-w-0 items-start gap-3">
          {iconBlock}
          <div className="min-w-0 flex-1">
            <h3 className="break-words text-[16px] font-[600] leading-[24px] font-poppins">
              {resolvedName}
            </h3>
            <p className="mt-[4px] inline-block max-w-full break-words px-[8px] py-[4px] text-center text-[12px] font-[500] leading-[16px] rounded-[32px] border border-[#E5E7EB]">
              {resolvedDomain}
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div
      onClick={onCtaClick}
      className={cn(
        "font-poppins flex h-full w-full min-w-0 max-w-[300px] cursor-pointer flex-col rounded-[12px] border border-[#E5E7EB] bg-white p-4",
        className,
      )}
    >
      <div className="flex min-w-0 items-start justify-between gap-2">
        <div className="shrink-0 self-start">{iconBlock}</div>
        <p className="w-fit max-w-full shrink-0 break-words px-[8px] text-right text-[12px] font-[500] leading-[16px] font-poppins rounded-[32px] border border-[#E5E7EB] py-[4px]">
          {resolvedDomain}
        </p>
      </div>
      <div className="mt-[12px] min-w-0">
        <h3 className="break-words text-[16px] font-[600] leading-[24px] font-poppins">
          {resolvedName}
        </h3>
        <p className="mt-[4px] break-words whitespace-pre-line text-[14px] font-[400] leading-[20px] font-poppins text-[#6B7280]">
          {resolvedMiniDescription}
        </p>
      </div>
      <div className="mt-auto flex justify-end pt-[20px]">
        <CardCtaButton
          text={resolvedCtaText}
          onClick={onCtaClick}
          theme={ctaTheme}
          className="leading-[12px]"
        />
      </div>
    </div>
  );
}

"use client";

import * as Dialog from "@radix-ui/react-dialog";
import { Users } from "@phosphor-icons/react";
import { X } from "lucide-react";
import { CardCtaButton } from "../shared/card-cta-button";
import type { ClubCardProps, DrawerDirection } from "./types";
import { RichContent } from "./rich-content";

import { cn } from "@/lib/utils";

function toCapitalizedWords(value: string) {
  return value.replace(/\b\w/g, (char) => char.toUpperCase());
}

/** Positive member count, or `null` to hide the badge (0, N/A, invalid). */
function parsePositiveMemberCount(value: number | string): number | null {
  if (typeof value === "number") {
    if (!Number.isFinite(value) || value <= 0) return null;
    return Math.floor(value);
  }
  const trimmed = value.trim();
  if (!trimmed || /^n\/?a$/i.test(trimmed)) return null;
  const parsed = Number.parseInt(trimmed.replace(/,/g, ""), 10);
  if (Number.isNaN(parsed) || parsed <= 0) return null;
  return parsed;
}

type ClubCardDrawerProps = Pick<
  ClubCardProps,
  | "domain"
  | "name"
  | "imageUrl"
  | "shouldCompress"
  | "totalMembers"
  | "detailPoints"
  | "detailDescription"
  | "ctaText"
  | "ctaTheme"
  | "onCtaClick"
  | "drawerBottomInsetClassName"
  | "drawerBodyClassName"
  | "drawerPinFooter"
  | "drawerFooterClassName"
> & {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  resolvedDirection: Exclude<DrawerDirection, "auto">;
};

export function ClubCardDrawer({
  domain,
  name,
  imageUrl,
  shouldCompress = false,
  totalMembers,
  detailPoints,
  detailDescription,
  ctaText,
  ctaTheme,
  onCtaClick,
  drawerBottomInsetClassName,
  drawerBodyClassName,
  drawerPinFooter = true,
  drawerFooterClassName,
  open,
  onOpenChange,
  resolvedDirection,
}: ClubCardDrawerProps) {
  const resolvedDomain = toCapitalizedWords(domain);
  const resolvedName = toCapitalizedWords(name);
  const resolvedCtaText = toCapitalizedWords(ctaText);
  const memberCount = parsePositiveMemberCount(totalMembers);

  const footerCta = (
    <div
      className={cn(
        "border-t bg-white p-4",
        drawerPinFooter && "shrink-0",
        drawerPinFooter &&
          resolvedDirection === "bottom" &&
          "shadow-[0_-4px_16px_rgba(0,0,0,0.06)]",
        !drawerPinFooter && "mt-6",
        drawerFooterClassName,
      )}
    >
      <CardCtaButton
        text={resolvedCtaText}
        onClick={onCtaClick}
        theme={ctaTheme}
        fullWidth
      />
    </div>
  );

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <Dialog.Portal>
        <Dialog.Overlay className="fixed inset-0 z-50 bg-black/50 transition-opacity duration-300 ease-out data-[state=closed]:opacity-0 data-[state=open]:opacity-100" />
        <Dialog.Content
          className={cn(
            "fixed z-50 border bg-white font-poppins shadow-xl outline-none",
            resolvedDirection === "right"
              ? "right-0 top-0 flex h-svh w-full max-w-[420px] flex-col border-l transition-transform duration-300 ease-out will-change-transform data-[state=closed]:translate-x-full data-[state=open]:translate-x-0"
              : "bottom-0 left-0 flex w-full max-h-[88svh] flex-col rounded-t-2xl border-t transition-transform duration-300 ease-out will-change-transform data-[state=closed]:translate-y-full data-[state=open]:translate-y-0",
            drawerBottomInsetClassName,
          )}
        >
          <div className="flex items-start justify-between gap-3 border-b p-4">
            <div className="min-w-0 flex-1">
              <p className="break-words text-xs font-semibold uppercase tracking-wide text-slate-500">
                {resolvedDomain}
              </p>
              <Dialog.Title className="mt-1 break-words text-lg font-semibold text-slate-900">
                About the Club
              </Dialog.Title>
            </div>
            <Dialog.Close className="inline-flex size-8 items-center justify-center rounded-md border text-slate-500 hover:bg-slate-50 hover:text-slate-800">
              <X className="size-4" />
              <span className="sr-only">Close</span>
            </Dialog.Close>
          </div>

          <div className="flex min-h-0 flex-1 flex-col p-4">
            <div className="bg-[#EBF5FF] flex py-[32px] rounded-[8px]">
              <img
                src={imageUrl}
                alt={resolvedName}
                className="h-[56px] w-[56px] m-auto"
              />
            </div>
            <div
              className={cn(
                "mt-[16px] min-h-0 min-w-0 flex-1 overflow-y-auto overflow-x-hidden pr-1",
                drawerBodyClassName,
              )}
            >
              <p className="break-words text-[18px] font-[600] leading-[28px] font-poppins text-[#111928]">
                {resolvedName}
              </p>
              <RichContent
                value={detailDescription}
                className="mt-[8px] text-[14px] font-[400] leading-[20px] font-poppins text-[#374151] [&_a]:underline [&_ol]:list-decimal [&_ol]:pl-5 [&_p]:mb-3 [&_p:last-child]:mb-0 [&_ul]:list-disc [&_ul]:pl-5"
              />
              {memberCount !== null ? (
                <div className="mt-[12px] flex w-fit items-center gap-[6px] rounded-[32px] border border-[#E5E7EB] px-[12px] py-[4px] text-[#111928]">
                  <Users size={20} aria-hidden="true" color="#374151" />
                  <p className="font-poppins text-[12px] font-[500] leading-[16px] text-[#374151]">
                    {memberCount}{" "}
                    {memberCount === 1 ? "member" : "members"}
                  </p>
                </div>
              ) : null}

              {detailPoints.length > 0 ? (
                <div className="mt-[32px]">
                  <h4 className="text-[14px] font-[600] leading-[20px] font-poppins text-[#111928]">
                    What you’ll do here
                  </h4>
                  <ul className="mt-[12px] list-disc gap-[4px] pl-5 text-[14px] font-[400] leading-[24px] font-poppins text-[#374151]">
                    {detailPoints.map((point, index) => (
                      <li key={`${point}-${index}`} className="break-words">
                        {toCapitalizedWords(point)}
                      </li>
                    ))}
                  </ul>
                </div>
              ) : null}

              {!drawerPinFooter && !shouldCompress ? footerCta : null}
            </div>
          </div>
          {drawerPinFooter && !shouldCompress ? footerCta : null}
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

"use client"

import { cn } from "@/lib/utils"
import ReactMarkdown from "react-markdown"
import rehypeRaw from "rehype-raw"
import rehypeSanitize, { defaultSchema } from "rehype-sanitize"
import remarkGfm from "remark-gfm"
import type { Options as SanitizeOptions } from "rehype-sanitize"

type RichContentProps = {
  value: string
  className?: string
}

const sanitizeSchema: SanitizeOptions = {
  ...defaultSchema,
  tagNames: [...(defaultSchema.tagNames ?? []), "video"],
  attributes: {
    ...(defaultSchema.attributes ?? {}),
    video: [
      "src",
      "controls",
      "poster",
      "preload",
      "playsInline",
      "muted",
      "loop",
      "width",
      "height",
    ],
    source: [...(defaultSchema.attributes?.source ?? []), "src", "type"],
  },
}

const HTML_ENTITY_MAP: Record<string, string> = {
  "&nbsp;": " ",
  "&amp;": "&",
  "&lt;": "<",
  "&gt;": ">",
  "&quot;": '"',
  "&#39;": "'",
}

function decodeHtmlEntities(value: string) {
  return Object.entries(HTML_ENTITY_MAP).reduce(
    (result, [entity, replacement]) => result.split(entity).join(replacement),
    value,
  )
}

function decodeMarkdownPayload(content: string): string {
  if (!content) return ""

  const normalizedContent = content
    .replace(/\\r\\n/g, "\n")
    .replace(/\\n/g, "\n")
    .replace(/\\t/g, "\t")

  if (normalizedContent.includes("&lt;") || normalizedContent.includes("&gt;")) {
    const parser = new DOMParser()
    const decoded = parser
      .parseFromString(normalizedContent, "text/html")
      .documentElement.textContent
    return decoded ?? normalizedContent
  }

  return normalizedContent
}

export function toRichPreviewText(value: string) {
  const decoded = decodeHtmlEntities(decodeMarkdownPayload(value || ""))

  return decoded
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<\/(p|div|li|h[1-6]|blockquote)>/gi, "\n")
    .replace(/<[^>]+>/g, " ")
    .replace(/!\[.*?\]\((.*?)\)/g, "$1")
    .replace(/\[(.*?)\]\((.*?)\)/g, "$1")
    .replace(/[#>*_`~-]/g, "")
    .replace(/[^\S\n]+/g, " ")
    .replace(/\n{3,}/g, "\n\n")
    .trim()
}

export function RichContent({ value, className }: RichContentProps) {
  if (!value.trim()) return null

  return (
    <div
      className={cn(
        "min-w-0 max-w-full break-words [&_a]:break-all [&_code]:break-all [&_li]:min-w-0 [&_li]:whitespace-pre-wrap [&_ol]:min-w-0 [&_p]:min-w-0 [&_p]:whitespace-pre-wrap [&_ul]:min-w-0",
        className,
      )}
    >
      <ReactMarkdown
        remarkPlugins={[remarkGfm]}
        rehypePlugins={[rehypeRaw, [rehypeSanitize, sanitizeSchema]]}
      >
        {decodeMarkdownPayload(value)}
      </ReactMarkdown>
    </div>
  )
}

type CardCtaButtonProps = {
  text: string;
  onClick?: () => void;
  theme?: "yellow" | "red" | "purple";
  fullWidth?: boolean;
  className?: string;
};

const THEME_CLASSES = {
  yellow: "bg-[#EF8833] text-[#fff] hover:bg-[#DC7A2D]",
  red: "bg-[#EF4444] text-white hover:bg-[#DC2626]",
  purple: "bg-[#6962AC] text-white hover:bg-[#5B5596]",
} as const;

export function CardCtaButton({
  text,
  onClick,
  theme = "yellow",
  fullWidth = false,
  className = "",
}: CardCtaButtonProps) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`inline-flex min-w-0 max-w-full cursor-pointer items-center justify-center rounded-[8px] px-[16px] py-[8px] text-[14px] font-[500] leading-[20px] font-poppins transition-colors ${fullWidth ? "w-full" : ""} ${THEME_CLASSES[theme]} ${className}`.trim()}
    >
      <span className="min-w-0 max-w-full whitespace-normal break-words text-center">{text}</span>
    </button>
  );
}
